var actionMsg = msg.payload;
if (actionMsg.type === "init_location") {
    flow.set("home_lat", actionMsg.data.lat);
    flow.set("home_lon", actionMsg.data.lon);
    flow.set("lat", actionMsg.data.lat);
    flow.set("lon", actionMsg.data.lon);
    flow.set("mode", "standby");
    flow.set("alt", 0);
    flow.set("speed", 0);
    flow.set("battery", 100);
    flow.set("armed", false);
    flow.set("heading", 0);

    var gcsCmd = {
        payload: {
            command: { lat: actionMsg.data.lat, lon: actionMsg.data.lon, zoom: 17, layer: "Esri Satellite" }
        }
    };

    var wifiRing = { payload: { name: "WiFi_Zone", lat: actionMsg.data.lat, lon: actionMsg.data.lon, radius: 150, color: "#00f2fe", weight: 2, dashArray: "5, 5", layer: "Range", fillOpacity: 0, tooltip: "WiFi Zone" } };
    var loraRing = { payload: { name: "LoRa_Zone", lat: actionMsg.data.lat, lon: actionMsg.data.lon, radius: 1000, color: "#eab308", weight: 2, dashArray: "10, 10", layer: "Range", fillOpacity: 0, tooltip: "LoRa Zone" } };
    var homePin = { payload: { name: "Home_Location", lat: actionMsg.data.lat, lon: actionMsg.data.lon, icon: "fa-home", iconColor: "#ef4444", layer: "Home", tooltip: "Home Base" } };

    var plannerCmd = { payload: { command: { lat: actionMsg.data.lat, lon: actionMsg.data.lon, zoom: 15, layer: "OSM", showlayer: "drawing" } } };

    return [[gcsCmd, wifiRing, loraRing, homePin], plannerCmd];
}

if (actionMsg.type === "clear_mission") {
    var clearCmd = { payload: { command: { clear: "Flight Path" } } };
    return [[clearCmd], null];
}

if (actionMsg.type === "clear_detections") {
    var clearCmd = { payload: { command: { clear: "Rescue Pins" } } };
    return [[clearCmd], null];
}

if (actionMsg.type === "recenter") {
    return [[{ payload: { command: { lat: actionMsg.data.lat, lon: actionMsg.data.lon, zoom: 17 } } }], null];
}

if (actionMsg.type === "add_pin") {
    var pin = {
        payload: {
            name: "Rescue_" + actionMsg.data.num,
            lat: actionMsg.data.lat,
            lon: actionMsg.data.lon,
            icon: "",
            iconColor: "#dc2626",
            layer: "Rescue Pins",
            label: "Pin " + actionMsg.data.num,
            popup: `<b>📍 PERSON DETECTED</b><br>Time: ${new Date().toLocaleTimeString()}<br>Confidence: ${85 + Math.floor(Math.random()*10)}%<br>GPS: ${actionMsg.data.lat.toFixed(5)}°N ${actionMsg.data.lon.toFixed(5)}°E<br><button onclick="alert('Coords exported!')">Export Coords</button>`
        }
    };
    return [[pin], null];
}

if (actionMsg.type === "thermal_overlay") {
    if (actionMsg.state) {
        var thermal = { payload: { name: "Thermal_Overlay", lat: actionMsg.lat, lon: actionMsg.lon, radius: 40, color: "transparent", fillColor: "#ef4444", fillOpacity: 0.5, layer: "Thermal", tooltip: "Thermal FOV" } };
        return [[thermal], null];
    } else {
        return [[{ payload: { deleted: true, name: "Thermal_Overlay" } }], null];
    }
}

if (actionMsg.action === "arm") {
    flow.set("armed", actionMsg.state);
    if (!actionMsg.state) { flow.set("mode", "standby"); flow.set("alt", 0); flow.set("speed", 0); }
} else if (actionMsg.action === "takeoff") {
    if (flow.get("armed")) flow.set("mode", "takeoff");
} else if (actionMsg.action === "land") {
    flow.set("mode", "land");
} else if (actionMsg.action === "rtl") {
    flow.set("mode", "rtl");
}
return null;

var home_lat = flow.get("home_lat");
var home_lon = flow.get("home_lon");

if (home_lat === undefined || home_lon === undefined) {
    return null;
}

var armed = flow.get("armed") || false;
var mode = flow.get("mode") || "standby";
var alt = flow.get("alt") || 0;
var speed = flow.get("speed") || 0;
var battery = flow.get("battery") === undefined ? 100 : flow.get("battery");
var lat = flow.get("lat") === undefined ? home_lat : flow.get("lat");
var lon = flow.get("lon") === undefined ? home_lon : flow.get("lon");
var heading = flow.get("heading") || 0;

if (armed) {
    battery = Math.max(0, battery - 0.03);

    if (mode === "takeoff") {
        alt = Math.min(30, alt + 1.5);
        speed = Math.min(6, speed + 0.5);
        heading = 45;
        if (alt >= 30) {
            mode = "hover";
        }
    } else if (mode === "hover") {
        alt += (Math.random() - 0.5) * 0.2;
        alt = Math.max(28, Math.min(32, alt));
        speed = Math.max(0.5, speed + (Math.random() - 0.5) * 0.3);
        lat += 0.00002 * Math.cos(heading * Math.PI / 180);
        lon += 0.00002 * Math.sin(heading * Math.PI / 180);
        heading = (heading + (Math.random() - 0.5) * 8) % 360;
    } else if (mode === "land") {
        alt = Math.max(0, alt - 1.2);
        speed = Math.max(0, speed - 0.4);
        if (alt <= 0) {
            mode = "standby";
            armed = false;
            speed = 0;
        }
    } else if (mode === "rtl") {
        var dLat = home_lat - lat;
        var dLon = home_lon - lon;
        var dist = Math.sqrt(dLat * dLat + dLon * dLon);
        if (dist < 0.00005) {
            mode = "land";
        } else {
            lat += (dLat / dist) * 0.00008;
            lon += (dLon / dist) * 0.00008;
            heading = Math.atan2(dLon, dLat) * 180 / Math.PI;
            if (heading < 0) heading += 360;
            speed = 8;
            alt += (30 - alt) * 0.1;
        }
    }
} else {
    mode = "standby";
    alt = 0;
    speed = 0;
    lat = home_lat;
    lon = home_lon;
    heading = 0;
    if (battery < 20) battery = 100;
}

flow.set("armed", armed);
flow.set("mode", mode);
flow.set("alt", alt);
flow.set("speed", speed);
flow.set("battery", battery);
flow.set("lat", lat);
flow.set("lon", lon);
flow.set("heading", heading);

var telemetry = {
    payload: {
        type: "telemetry",
        data: {
            armed: armed,
            mode: mode,
            alt: alt,
            speed: speed,
            battery: Math.floor(battery),
            pitch: armed ? (mode === "takeoff" ? 12 : (mode === "land" ? -8 : (Math.random() - 0.5) * 3)) : 0,
            roll: armed ? (Math.random() - 0.5) * 5 : 0,
            heading: Math.floor(heading),
            lat: lat,
            lon: lon,
            home_lat: home_lat,
            home_lon: home_lon
        }
    }
};

// Use an arrow icon facing the heading direction

var isError = (battery < 20); // Basic error condition

var markerColor = "#4facfe"; // light blue when disarmed
if (isError) {
    markerColor = "#e74c3c"; // red when error
} else if (armed) {
    markerColor = "#2ecc71"; // green when armed
}

var marker = {
    payload: {
        name: "Drone",
        lat: lat,
        lon: lon,
        icon: "quad",
        iconColor: markerColor,
        bearing: heading,
        iconSize: 48,
        layer: "Drone Location"
    }
};

return [telemetry, marker];

var event = msg.payload;

// 1. Handle client connection (when the user opens/refreshes the Waypoint Planner tab)
if (event.action === "connected") {
    var home_lat = flow.get("home_lat");
    var home_lon = flow.get("home_lon");
    if (home_lat !== undefined && home_lon !== undefined) {
        // Send command directly back to the specific connection session
        msg.payload = {
            command: {
                lat: home_lat,
                lon: home_lon,
                zoom: 15,
                layer: "OSM",
                showlayer: "drawing"
            }
        };
        return [msg, null];
    }
}

// 2. Handle drawing actions (draw/drawdelete/drawupdate)
if (event.action === "draw" || event.action === "drawdelete" || event.action === "drawupdate") {
    // Map the layer from "_drawing" to "Flight Path" so it shows up cleanly on GCS Map without showing the drawing toolbar
    if (event.layer === "_drawing") {
        event.layer = "Flight Path";
    }

    var forwardMsg = {
        payload: event
    };
    return [null, forwardMsg];
}

return null;
